(function () {
  const CHARTJS_CDN = "https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js";
  const ROOT_ID = "root";
  const POLL_MODEL_MS = 2000;
  const CHART_COLORS = ["#0088FE", "#00C49F", "#FFBB28", "#FF8042", "#A020F0", "#FF6666", "#67C23A", "#4BC0C0", "#9966FF"];
  async function loadScript(url) {
    return new Promise((resolve, reject) => {
      if (window.Chart) return resolve();
      const s = document.createElement("script");
      s.src = url;
      s.async = true;
      s.onload = () => resolve();
      s.onerror = e => reject(e);
      document.head.appendChild(s);
    });
  }
  function ensureRoot() {
    let root = document.getElementById(ROOT_ID);
    if (!root) {
      root = document.createElement("div");
      root.id = ROOT_ID;
      document.body.appendChild(root);
    }
    root.innerHTML = "";
    return root;
  }
  function formatNumber(v) {
    if (v === null || v === undefined) return 0;
    if (typeof v === "number") return v;
    const n = Number(String(v).replace(/,/g, ""));
    return isNaN(n) ? 0 : n;
  }
  function normalizeUtilityData(arr) {
    if (!Array.isArray(arr)) return [];
    return arr.map(r => {
      const utility_type = r.utility_type ?? "UNKNOWN";
      const total_cost_raw = r.total_cost ?? r.totalCost ?? r.cost ?? r.value ?? 0;
      const total_cost = Number(formatNumber(total_cost_raw)) || 0;
      return {
        utility_type: String(utility_type),
        total_cost
      };
    });
  }
  function normalizeGenericRows(rows) {
    if (!Array.isArray(rows)) return [];
    return rows.map(r => {
      const out = {};
      for (const k in r) {
        const v = r[k];
        if (typeof v === "string" && isNaN(Number(v))) {
          out[k] = v;
        } else {
          out[k] = formatNumber(v);
        }
      }
      return out;
    });
  }
  let chartsState = [];
  let activeChartsInstances = {};
  function clearChartsInstances() {
    for (const key in activeChartsInstances) {
      try {
        activeChartsInstances[key].destroy();
      } catch (e) {}
    }
    activeChartsInstances = {};
  }
  function createMenu(chartId, chartName, onClose) {
    const menu = document.createElement("div");
    menu.className = "menu-popup";
    menu.style.position = "absolute";
    menu.style.top = "100%";
    menu.style.right = "0";
    menu.style.background = "#fff";
    menu.style.border = "1px solid #ccc";
    menu.style.borderRadius = "4px";
    menu.style.boxShadow = "0 2px 6px rgba(0,0,0,0.15)";
    menu.style.minWidth = "100px";
    menu.style.zIndex = 1000;
    const makeItem = (label, action) => {
      const it = document.createElement("div");
      it.className = "menu-item";
      it.style.padding = "6px 12px";
      it.style.cursor = "pointer";
      it.textContent = label;
      it.onmouseover = () => it.style.background = "#f0f0f0";
      it.onmouseout = () => it.style.background = "transparent";
      it.onclick = e => {
        e.stopPropagation();
        if (action === "VIEW") appsmith.triggerEvent("onFullView", {
          id: chartId,
          name: (chartName || "").replace(/\s+/g, "")
        });
        if (action === "EDIT") appsmith.triggerEvent("onEditChart", {
          id: chartId
        });
        if (action === "REMOVE") appsmith.triggerEvent("onRemoveChart", {
          id: chartId
        });
        onClose && onClose();
      };
      return it;
    };
    menu.appendChild(makeItem("Full View", "VIEW"));
    menu.appendChild(makeItem("Edit", "EDIT"));
    menu.appendChild(makeItem("Remove", "REMOVE"));
    return menu;
  }

  // Wait for the particular chart's rows to become available (used per-chart)
  async function waitForChartDataForItem(getRowsFn, timeout = 10000, interval = 500) {
    const start = Date.now();
    return new Promise(resolve => {
      const check = () => {
        try {
          const rows = getRowsFn();
          if (Array.isArray(rows) && rows.length > 0) return resolve(rows);
        } catch (e) {
          // ignore and retry
        }
        if (Date.now() - start > timeout) return resolve([]); // fallback empty
        setTimeout(check, interval);
      };
      check();
    });
  }
  function makeChartCard(item, index) {
    const id = `chart-card-${item.id}-${index}`;
    const card = document.createElement("div");
    card.className = "chart-item";
    card.setAttribute("data-index", index);
    card.setAttribute("data-id", item.id);
    card.setAttribute("draggable", "false");
    card.style.flex = `1 1 calc(50% - 20px)`;
    card.style.minHeight = "280px";
    card.style.border = "1px solid #ccc";
    card.style.borderRadius = "8px";
    card.style.padding = "8px";
    card.style.boxShadow = "0 2px 6px rgba(0,0,0,0.1)";
    card.style.background = "#fff";
    card.style.display = "flex";
    card.style.flexDirection = "column";

    // Header
    const header = document.createElement("div");
    header.style.display = "flex";
    header.style.alignItems = "center";
    header.style.marginBottom = "8px";
    const handle = document.createElement("span");
    handle.textContent = "✥";
    handle.title = "Drag";
    handle.style.cursor = "grab";
    handle.style.marginRight = "6px";
    handle.style.userSelect = "none";
    header.appendChild(handle);
    const title = document.createElement("span");
    title.textContent = item.name || "Untitled";
    title.style.flex = "1";
    header.appendChild(title);
    const menuWrap = document.createElement("div");
    menuWrap.style.position = "relative";
    const menuIcon = document.createElement("span");
    menuIcon.innerHTML = "&#x22EE;";
    menuIcon.style.cursor = "pointer";
    menuWrap.appendChild(menuIcon);
    header.appendChild(menuWrap);
    card.appendChild(header);
    const content = document.createElement("div");
    content.style.flex = "1";
    content.style.display = "flex";
    content.style.alignItems = "center";
    content.style.justifyContent = "center";
    card.appendChild(content);

    // Menu popup
    let popup = null;
    function closeMenu() {
      if (popup?.parentNode) popup.parentNode.removeChild(popup);
      popup = null;
    }
    menuIcon.addEventListener("click", e => {
      e.stopPropagation();
      if (popup) {
        closeMenu();
        return;
      }
      popup = createMenu(item.id, item.name, closeMenu);
      menuWrap.appendChild(popup);
      setTimeout(() => {
        const onDoc = ev => {
          if (!menuWrap.contains(ev.target)) {
            closeMenu();
            document.removeEventListener("mousedown", onDoc);
          }
        };
        document.addEventListener("mousedown", onDoc);
      }, 0);
    });

    // Drag & Drop
    let draggingEnabled = false;
    handle.addEventListener("mousedown", e => {
      e.stopPropagation();
      draggingEnabled = true;
      handle.style.cursor = "grabbing";
      card.setAttribute("draggable", "true");
    });
    window.addEventListener("mouseup", () => {
      if (draggingEnabled) {
        draggingEnabled = false;
        handle.style.cursor = "grab";
        card.setAttribute("draggable", "false");
      }
    });
    card.addEventListener("dragstart", e => {
      if (!draggingEnabled) {
        e.preventDefault();
        return;
      }
      e.dataTransfer.setData("text/plain", index);
      card.style.opacity = "0.4";
    });
    card.addEventListener("dragend", () => {
      card.style.opacity = "1";
      draggingEnabled = false;
      handle.style.cursor = "grab";
      card.setAttribute("draggable", "false");
    });
    card.addEventListener("dragover", e => e.preventDefault());
    card.addEventListener("drop", e => {
      e.preventDefault();
      const draggedIndex = Number(e.dataTransfer.getData("text/plain"));
      const droppedIndex = Number(card.getAttribute("data-index"));
      if (!isNaN(draggedIndex) && draggedIndex !== droppedIndex) reorderCharts(draggedIndex, droppedIndex);
    });

    // Chart Rendering - async so we can wait for chartData if it arrives after initial render
    (async function renderInner() {
      try {
        const chartDataAvailable = appsmith?.model?.chartData || {};
        const getRows = () => {
          if (item.type === "cost_by_utility") {
            return chartDataAvailable.CostsbyUtilityType || [];
          } else {
            const dataKeyMap = {
              "highest_unit_cost_locations": "HighestUnitCostLocations",
              "highest_cost_locations": "HighestCostLocations",
              "charges_by_vendor": "ChargesByVendor",
              "costs_by_charge_type": "CostsbyChargeType",
              "monthly_cost_by_location": "MonthlyCostbyLocation",
              "highest_consumption_locations": "HighestConsumptionLocations",
              "monthly_consumption_by_location": "MonthlyConsumptionbyLocation"
            };
            const chartDataKey = dataKeyMap[item.type] || item.type;
            return chartDataAvailable[chartDataKey] || [];
          }
        };

        // Wait for this chart's data up to 10s (polling every 500ms)
        let rows = await waitForChartDataForItem(getRows, 10000, 500);
        if (!rows.length) {
          content.innerHTML = "No Data";
          return;
        }

        // Pie chart: cost_by_utility
        if (item.type === "cost_by_utility") {
          const normalizedData = normalizeUtilityData(rows).sort((a, b) => b.total_cost - a.total_cost);
          const top = normalizedData.slice(0, 3).map(r => ({
            x: r.utility_type,
            y: r.total_cost
          }));
          const others = normalizedData.slice(3);
          if (others.length) top.push({
            x: "Others",
            y: others.reduce((sum, r) => sum + r.total_cost, 0)
          });
          rows = top;
          const labels = rows.map(r => r.x);
          const values = rows.map(r => r.y);
          const bgColors = labels.map((_, i) => CHART_COLORS[i % CHART_COLORS.length]);
          content.innerHTML = "";
          const canvas = document.createElement("canvas");
          content.appendChild(canvas);
          const ctx = canvas.getContext("2d");
          activeChartsInstances[id] = new Chart(ctx, {
            type: "pie",
            data: {
              labels,
              datasets: [{
                data: values,
                backgroundColor: bgColors
              }]
            },
            options: {
              responsive: true,
              maintainAspectRatio: false,
              plugins: {
                legend: {
                  position: "bottom"
                }
              }
            }
          });
          return;
        }

        // Generic bar chart
        rows = normalizeGenericRows(rows);
        const sample = rows[0];
        const xKey = Object.keys(sample).find(k => ["location_description", "name", "vendor_name", "charge_type"].includes(k)) || Object.keys(sample)[0];
        const yKeys = Object.keys(sample).filter(k => k !== xKey && typeof sample[k] === "number");
        if (yKeys.length === 0) {
          content.innerHTML = "No numeric data";
          return;
        }
        const labels = rows.map(r => r[xKey]);
        const datasets = yKeys.map((yk, i) => ({
          label: yk.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()),
          data: rows.map(r => r[yk]),
          backgroundColor: CHART_COLORS[i % CHART_COLORS.length]
        }));
        const showLegend = datasets.length > 1;
        content.innerHTML = "";
        const canvas = document.createElement("canvas");
        content.appendChild(canvas);
        const ctx = canvas.getContext("2d");
        activeChartsInstances[id] = new Chart(ctx, {
          type: "bar",
          data: {
            labels,
            datasets
          },
          options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
              legend: {
                position: "bottom",
                display: showLegend
              }
            }
          }
        });
      } catch (err) {
        console.error(err);
        content.innerHTML = "Error rendering chart";
      }
    })();
    return card;
  }
  function reorderCharts(fromIndex, toIndex) {
    const copy = chartsState.slice();
    const [moved] = copy.splice(fromIndex, 1);
    copy.splice(toIndex, 0, moved);
    chartsState = copy;
    renderGrid();
    try {
      appsmith.triggerEvent("onOrderChange", copy.map((c, i) => ({
        id: c.id,
        new_sort_order: i + 1
      })));
    } catch (e) {}
  }
  async function renderGrid() {
    clearChartsInstances();
    const root = ensureRoot();
    const wrapper = document.createElement("div");
    wrapper.className = "app";
    const grid = document.createElement("div");
    grid.className = "chart-grid";
    grid.style.display = "flex";
    grid.style.flexWrap = "wrap";
    grid.style.gap = "20px";
    chartsState.forEach((c, i) => grid.appendChild(makeChartCard(c, i)));
    wrapper.appendChild(grid);
    root.innerHTML = "";
    root.appendChild(wrapper);
  }
  async function waitForChartsData(timeout = 5000, interval = 500) {
    const start = Date.now();
    return new Promise((resolve, reject) => {
      const check = () => {
        const data = appsmith?.model?.charts;
        if (Array.isArray(data) && data.length > 0) return resolve(data);
        if (Date.now() - start > timeout) return reject("Charts data not loaded in time");
        setTimeout(check, interval);
      };
      check();
    });
  }
  async function init() {
    try {
      await loadScript(CHARTJS_CDN);
    } catch (e) {
      console.error(e);
      return;
    }
    try {
      chartsState = await waitForChartsData();
    } catch (err) {
      console.warn(err);
      chartsState = [];
    }
    await renderGrid();

    // Watcher for changes to the charts list (ordering / new chart items)
    let prevChartsJson = JSON.stringify(appsmith?.model?.charts);
    setInterval(() => {
      try {
        const curr = appsmith?.model?.charts;
        const currJson = JSON.stringify(curr);
        if (currJson !== prevChartsJson) {
          prevChartsJson = currJson;
          chartsState = Array.isArray(curr) ? curr.slice() : [];
          renderGrid();
        }
      } catch (e) {}
    }, POLL_MODEL_MS);

    // NEW: Watcher for chartData arriving/changes — re-render when chartData updates
    let prevChartDataJson = JSON.stringify(appsmith?.model?.chartData);
    setInterval(() => {
      try {
        const curr = appsmith?.model?.chartData;
        const currJson = JSON.stringify(curr);
        if (currJson !== prevChartDataJson) {
          prevChartDataJson = currJson;
          // If chartData changes, re-render the grid so per-chart wait logic runs again (and charts pick up data)
          renderGrid();
        }
      } catch (e) {}
    }, POLL_MODEL_MS);
  }
  appsmith.onReady(init);
})();

